import React, { useState, useEffect } from 'react';
import './App.css';

import companyLogo from './assets/logo.png';

interface Deployment {
  customer: string;
  project: string;
  environment: string;
  branch: string;
  commit: string;
  user: string;
  email: string;
  releaseDate: string;
  buildDate: string;
}

interface ApiResponse {
  pageNumber: number;
  pageSize: number;
  total: number;
  results: Deployment[];
}

interface CustomerGroup {
  customer: string;
  deployments: Deployment[];
  isExpanded: boolean;
}

type Environment = 'PROD' | 'STAGE' | 'TEST';

// CONFIGURATION: Update these with your actual GitHub Org and Repo name
const GITHUB_ORG = "keros-dev";
const GITHUB_REPO = "KNimbus-2017";

function App() {
  const [deployments, setDeployments] = useState<Deployment[]>([]);
  const [filteredDeployments, setFilteredDeployments] = useState<Deployment[]>([]);
  const [customerGroups, setCustomerGroups] = useState<CustomerGroup[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedEnv, setSelectedEnv] = useState<Environment>('PROD');

  const getLatestDeployments = (data: Deployment[]): Deployment[] => {
    const map = new Map<string, Deployment>();
    data.forEach((dep) => {
      const key = `$${dep.customer}-$${dep.project}-${dep.environment}`;
      const existing = map.get(key);
      if (!existing || new Date(dep.releaseDate) > new Date(existing.releaseDate)) {
        map.set(key, dep);
      }
    });
    return Array.from(map.values()).sort(
      (a, b) => new Date(b.releaseDate).getTime() - new Date(a.releaseDate).getTime()
    );
  };

  const groupByCustomer = (data: Deployment[]): CustomerGroup[] => {
    const groups = new Map<string, Deployment[]>();

    data.forEach((dep) => {
      if (!groups.has(dep.customer)) {
        groups.set(dep.customer, []);
      }
      groups.get(dep.customer)!.push(dep);
    });

    // Sort deployments within each group by date (newest first)
    const result: CustomerGroup[] = Array.from(groups.entries()).map(([customer, deps]) => ({
      customer,
      deployments: deps.sort(
        (a, b) => new Date(b.releaseDate).getTime() - new Date(a.releaseDate).getTime()
      ),
      isExpanded: true // Default to expanded
    }));

    // Sort customers alphabetically
    return result.sort((a, b) => a.customer.localeCompare(b.customer));
  };

  const fetchDeployments = async (env: Environment) => {
    try {
      setLoading(true);
      setError(null);
      const response = await fetch(`/release/all/${env}`);
      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }
      const data: ApiResponse = await response.json();
      setDeployments(data.results);
      const latest = getLatestDeployments(data.results);
      setFilteredDeployments(latest);
      setCustomerGroups(groupByCustomer(latest));
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
      console.error('Error fetching data:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDeployments(selectedEnv);
  }, []);

  const handleEnvChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const newEnv = event.target.value as Environment;
    setSelectedEnv(newEnv);
    fetchDeployments(newEnv);
  };

  const toggleCustomerGroup = (index: number) => {
    setCustomerGroups(prev => 
      prev.map((group, i) => 
        i === index ? { ...group, isExpanded: !group.isExpanded } : group
      )
    );
  };

  const toggleAllGroups = (expand: boolean) => {
    setCustomerGroups(prev => 
      prev.map(group => ({ ...group, isExpanded: expand }))
    );
  };

  const formatDate = (dateString: string) => {
    if (dateString === '0001-01-01T00:00:00') return '-';
    const date = new Date(dateString);

    // Custom formatting to ensure yyyy/MM/dd HH:mm
    const pad = (num: number) => num.toString().padStart(2, '0');

    const year = date.getFullYear();
    const month = pad(date.getMonth() + 1); // Months are 0-indexed
    const day = pad(date.getDate());
    const hours = pad(date.getHours());
    const minutes = pad(date.getMinutes());

    return `${year}/${month}/${day} ${hours}:${minutes}`;
  };

  const getEnvironmentBadge = (env: string) => {
    const colors: Record<string, string> = {
      PROD: '#dc3545',
      STAGE: '#ffc107',
      TEST: '#28a745'
    };
    return colors[env] || '#6c757d';
  };

  const getGitHubUrl = (commitHash: string, projectName?: string) => {
    return `https://github.com/${GITHUB_ORG}/${GITHUB_REPO}/commit/${commitHash}`;
  };

  return (
    <div className="App">
      <header className="App-header">
        {/* Logo Image */}
          <img 
            src={companyLogo} 
            alt="Company Logo" 
            className="app-logo" 
          />
        <h1>Deploy Tracker</h1>
        <div className="controls">
          <label htmlFor="env-select">Environment:</label>
          <select 
            id="env-select" 
            value={selectedEnv} 
            onChange={handleEnvChange}
            disabled={loading}
          >
            <option value="PROD">PROD</option>
            <option value="STAGE">STAGE</option>
            <option value="TEST">TEST</option>
          </select>
          <button 
            onClick={() => fetchDeployments(selectedEnv)} 
            disabled={loading}
            className="refresh-btn"
          >
            {loading ? 'Loading...' : 'Refresh'}
          </button>
        </div>
      </header>

      <main className="App-main">
        {!loading && !error && (
          <div className="stats">
            <span>Customers: {customerGroups.length} / Deployments: {filteredDeployments.length}</span>
            <div className="bulk-controls">
              <button onClick={() => toggleAllGroups(true)} className="bulk-btn">Expand All</button>
              <button onClick={() => toggleAllGroups(false)} className="bulk-btn">Collapse All</button>
            </div>
          </div>
        )}

        {loading && <div className="loading">Loading data...</div>}

        {error && <div className="error">❌ Error: {error}</div>}

        {!loading && !error && customerGroups.length === 0 && (
          <div className="no-data">No deployments found for {selectedEnv}</div>
        )}

        {!loading && !error && customerGroups.length > 0 && (
          <div className="grouped-table-container">
            {customerGroups.map((group, groupIndex) => (
              <div key={group.customer} className="customer-group">
                {/* Customer Header Row */}
                <div 
                  className="customer-header"
                  onClick={() => toggleCustomerGroup(groupIndex)}
                >
                  <span className={`toggle-icon ${group.isExpanded ? 'expanded' : 'collapsed'}`}>
                    ▶
                  </span>
                  <span className="customer-name">{group.customer}</span>
                  <span className="deployment-count">
                    {group.deployments.length} deployment{group.deployments.length !== 1 ? 's' : ''}
                  </span>
                </div>

                {/* Deployments Table (shown when expanded) */}
                {group.isExpanded && (
                  <table className="deployment-table">
                    <thead>
                      <tr>
                        <th>Project</th>
                        <th>Environment</th>
                        <th>Branch</th>
                        <th>Commit</th>
                        <th>Deployer</th>
                        <th>Release Date</th>
                      </tr>
                    </thead>
                    <tbody>
                      {group.deployments.map((dep, depIndex) => {
                        const commitLink = getGitHubUrl(dep.commit, dep.project);
                        return (
                          <tr key={`$${group.customer}-$${depIndex}`}>
                            <td>{dep.project}</td>
                            <td>
                              <span 
                                className="badge"
                                style={{ backgroundColor: getEnvironmentBadge(dep.environment) }}
                              >
                                {dep.environment}
                              </span>
                            </td>
                            <td>{dep.branch}</td>
                            <td className="commit">
                              <a 
                                href={commitLink} 
                                target="_blank" 
                                rel="noopener noreferrer"
                                title={`View commit ${dep.commit}`}
                                className="commit-link"
                              >
                                {dep.commit.substring(0, 7)} ↗
                              </a>
                            </td>
                            <td>{dep.user}</td>
                            <td>{formatDate(dep.releaseDate)}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                )}
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
